// Stack implementation
class Stack {
  constructor() { this.items = []; }
  push(el) { this.items.push(el); }
  pop() { return this.items.pop(); }
  peek() { return this.items[this.items.length-1]; }
}

// Stack code - used array methods
function Stack() { this.arr = []; }
Stack.prototype.push = function(x) { this.arr.push(x); };
Stack.prototype.pop = function() { return this.arr.pop(); };

// Stack with TypeScript style
const stack = [];
const push = (x) => stack.push(x);
const pop = () => stack.pop();
const peek = () => stack[stack.length-1];

// In-order, pre-order, post-order traversals
function inorder(node) { if (node) { inorder(node.left); console.log(node.val); inorder(node.right); } }
function preorder(node) { if (node) { console.log(node.val); preorder(node.left); preorder(node.right); } }
